import{_ as s,o as e,c as n,ak as i}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"事务、锁与 MVCC","description":"","frontmatter":{},"headers":[],"relativePath":"mysql/transaction/index.md","filePath":"mysql/transaction/index.md","lastUpdated":1774248380000}'),l={name:"mysql/transaction/index.md"};function t(r,a,o,c,d,h){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="事务、锁与-mvcc" tabindex="-1">事务、锁与 MVCC <a class="header-anchor" href="#事务、锁与-mvcc" aria-label="Permalink to “事务、锁与 MVCC”">​</a></h1><p>凌晨 2 点，你的电商系统突然出现大量超时——用户无法下单，无法支付。</p><p>监控显示 MySQL 连接数飙升，大量线程处于 LOCK WAIT 状态。</p><p>这不是查询慢的问题，而是<strong>锁冲突</strong>。</p><p>理解 MySQL 的事务、锁和 MVCC 机制，是在生产环境排查并发问题的必备技能。</p><hr><h2 id="内容地图" tabindex="-1">内容地图 <a class="header-anchor" href="#内容地图" aria-label="Permalink to “内容地图”">​</a></h2><p>本模块是 MySQL 最核心的进阶知识——事务保证数据一致性，锁保证并发安全，MVCC 让一切在高性能下运转。</p><h3 id="事务基础" tabindex="-1">事务基础 <a class="header-anchor" href="#事务基础" aria-label="Permalink to “事务基础”">​</a></h3><ul><li><a href="/database/mysql/transaction/basic">事务 ACID 与使用方式</a></li><li><a href="/database/mysql/transaction/isolation">隔离级别与并发问题：脏读/不可重复读/幻读</a></li></ul><h3 id="innodb-锁机制" tabindex="-1">InnoDB 锁机制 <a class="header-anchor" href="#innodb-锁机制" aria-label="Permalink to “InnoDB 锁机制”">​</a></h3><ul><li><a href="/database/mysql/transaction/lock/basic">锁概述：共享锁/排他锁/记录锁/间隙锁/临键锁</a></li><li><a href="/database/mysql/transaction/lock/table">表锁与元数据锁：ALTER TABLE 锁表的原因</a></li><li><a href="/database/mysql/transaction/lock/row">行锁详解：记录锁/间隙锁/临键锁的完整场景</a></li><li><a href="/database/mysql/transaction/lock/optimistic-pessimistic">乐观锁、悲观锁、死锁：选哪种锁策略</a></li><li><a href="/database/mysql/transaction/lock/monitor">锁监控与内存结构：如何排查锁问题</a></li></ul><h3 id="mvcc-多版本并发控制" tabindex="-1">MVCC 多版本并发控制 <a class="header-anchor" href="#mvcc-多版本并发控制" aria-label="Permalink to “MVCC 多版本并发控制”">​</a></h3><ul><li><a href="/database/mysql/transaction/mvcc/basic">MVCC 核心：隐藏字段/UndoLog/ReadView</a></li><li><a href="/database/mysql/transaction/mvcc/isolation">MVCC 与隔离级别：RC 和 RR 的本质区别</a></li></ul><h3 id="日志体系" tabindex="-1">日志体系 <a class="header-anchor" href="#日志体系" aria-label="Permalink to “日志体系”">​</a></h3><ul><li><a href="/database/mysql/transaction/log/index">日志概述：Binlog/RedoLog/UndoLog 的角色分工</a></li><li><a href="/database/mysql/transaction/log/basic">通用查询日志与错误日志：日常诊断工具</a></li><li><a href="/database/mysql/transaction/log/redo-undo">Redo Log 与 Undo Log：持久性与原子性的保障</a></li><li><a href="/database/mysql/transaction/log/binlog">Binlog：主从复制与数据恢复的基石</a></li></ul><hr><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to “学习路径”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一天：理解事务 ACID + 隔离级别（与并发问题有什么关系）</span></span>
<span class="line"><span>第二天：掌握锁机制（表锁/行锁/间隙锁，临键锁如何防幻读）</span></span>
<span class="line"><span>第三天：深入 MVCC（ReadView 的创建时机，RC vs RR 的区别）</span></span>
<span class="line"><span>第四天：理解日志体系（Redo/Binlog/Undo 各自的作用，两阶段提交）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>建议从 <a href="/database/mysql/transaction/basic">事务基础</a> 入手，理解 ACID 特性，然后学习 <a href="/database/mysql/transaction/isolation">隔离级别</a>，搞清楚脏读、不可重复读、幻读是怎么发生的。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to “下一步”">​</a></h2><p>事务是什么？ACID 特性怎么保证？显式事务和隐式事务有什么区别？</p><p>从 <a href="/database/mysql/transaction/basic">事务基础</a> 开始。</p>`,24)])])}const m=s(l,[["render",t]]);export{b as __pageData,m as default};
